import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const Login = () => {
  const [formData, setFormData] = useState({
    LoginName: '',
    Password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthLogin', formData);
      if (!response.data) {
        throw new Error('No response data received from server');
      }
      const token = response.data.Token;
      if (!token) {
        throw new Error('No token received from server');
      }
      let userInfo;
      try {
        const tokenData = JSON.parse(atob(token.split('.')[1]));
        userInfo = {
          Username: formData.LoginName,
          ClientCode: tokenData.ClientCode
        };
        if (!userInfo.ClientCode) {
          throw new Error('Client code not found in token');
        }
      } catch (tokenError) {
        throw new Error('Failed to extract client code from token');
      }
      localStorage.setItem('token', token);
      localStorage.setItem('userInfo', JSON.stringify(userInfo));
      toast.success(`Welcome ${userInfo.Username}!`, {
        position: "top-right",
        autoClose: 2000,
        theme: "colored"
      });
      navigate('/dashboard');
    } catch (err) {
      const errorMessage = err.response?.data?.Message || err.message || 'Login failed. Please try again.';
      setError(errorMessage);
      toast.error(errorMessage, {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: '#f6f7fb',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif'
    }}>
      <ToastContainer />
      <div style={{
        minWidth: 350,
        maxWidth: 370,
        width: '100%',
        background: '#fff',
        borderRadius: 16,
        boxShadow: '0 8px 32px 0 rgba(60,60,100,0.10)',
        padding: '2.5rem 2rem',
        margin: '2rem 0'
      }}>
        <h3 className="mb-4 fw-bold" style={{ fontSize: '1.45rem', color: '#222', textAlign: 'center', letterSpacing: 0.5 }}>Log in to your account</h3>
        {error && (
          <div className="alert alert-danger py-2" style={{ fontSize: '0.98rem' }}>{error}</div>
        )}
        <form onSubmit={handleSubmit} autoComplete="off">
          <div className="mb-3">
            <label htmlFor="LoginName" className="form-label" style={{ fontWeight: 500, color: '#222' }}>Email</label>
            <input
              type="text"
              className="form-control"
              id="LoginName"
              name="LoginName"
              value={formData.LoginName}
              onChange={handleChange}
              required
              placeholder="Enter your email"
              style={{ fontSize: '1.05rem', background: '#f6f7fb', border: '1px solid #e0e0e0', borderRadius: 8 }}
            />
          </div>
          <div className="mb-3 position-relative">
            <label htmlFor="Password" className="form-label" style={{ fontWeight: 500, color: '#222' }}>Password</label>
            <input
              type={showPassword ? 'text' : 'password'}
              className="form-control"
              id="Password"
              name="Password"
              value={formData.Password}
              onChange={handleChange}
              required
              placeholder="Enter password"
              style={{ fontSize: '1.05rem', background: '#f6f7fb', border: '1px solid #e0e0e0', borderRadius: 8 }}
            />
            <span
              onClick={() => setShowPassword(s => !s)}
              style={{
                position: 'absolute',
                right: 14,
                top: 38,
                cursor: 'pointer',
                color: '#888',
                fontSize: '1.1rem'
              }}
              tabIndex={0}
              role="button"
              aria-label="Toggle password visibility"
            >
              <i className={`fas ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
            </span>
          </div>
          <button
            type="submit"
            className="btn w-100 fw-bold"
            style={{
              fontSize: '1.08rem',
              background: '#2563eb',
              color: '#fff',
              border: 'none',
              borderRadius: 8,
              marginTop: 8,
              marginBottom: 8,
              boxShadow: '0 2px 8px rgba(37,99,235,0.10)',
              transition: 'background 0.2s'
            }}
            disabled={loading}
          >
            {loading ? (
              <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
            ) : (
              'Sign in'
            )}
          </button>
        </form>
        <div className="text-center mt-2" style={{ fontSize: '0.98rem', color: '#444' }}>
          Don&apos;t have an account?{' '}
          <span
            className="fw-bold"
            style={{ color: '#2563eb', cursor: 'pointer' }}
            onClick={() => navigate('/register')}
          >
            Sign up now
          </span>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Login;
